//   A (hp % 4 == 1) = 3, B (hp % 4 == 3) = 2, C (hp % 4 == 2) = 1, D (hp % 4 == 0) = 0
// Encoding the ordering A > B > C > D as 3 > 2 > 1 > 0.
ghost function CategoryRank(hp: int): int
  requires hp >= 1
{
  var r := hp % 4;
  if r == 1 then 3
  else if r == 3 then 2
  else if r == 2 then 1
  else 0
}

// Maps HP to its category character per the problem statement.
